use raytracer::Vec3;
use raytracer::Color;
use raytracer::Dielectric;
use raytracer::Point3;
use raytracer::Sphere;
use raytracer::HittableList;
use raytracer::Camera;
use raytracer::Lambertian;
use raytracer::Metal;
use raytracer::Triangle;
use raytracer::utils::random_real;
use raytracer::utils::random_real_interval;
use raytracer::utils::random_integer_interval;

use std::sync::Arc;

// Test scenario generated by GPT.

fn main() {
    let mut world: HittableList = HittableList::default();

    let material_ground = Arc::new(Lambertian::new(0.5, 0.5, 0.5));
    world.push(Box::new(Sphere::new(Point3::new(0.0, -1000.0, -1.0), 1000.0, material_ground)));

    let mut rng = rand::thread_rng();

    // Add many small triangles with varied sizes, orientations and materials
    for a in -18..18 {
        for b in -18..18 {
            let choose_mat = random_real(&mut rng);
            let center = Point3::new(
                (a as f64) + 0.9 * random_real(&mut rng),
                0.15,
                (b as f64) + 0.9 * random_real(&mut rng)
            );

            if (center - Point3::new(4.0, 0.2, 0.0)).length() > 0.9 {
                if choose_mat < 0.75 {
                    // many small diffuse triangles
                    let size = random_real_interval(&mut rng, 0.05, 0.5);
                    let angle = random_real_interval(&mut rng, 0.0, std::f64::consts::PI * 2.0);

                    let dx1 = size * angle.cos();
                    let dz1 = size * angle.sin();
                    let dx2 = size * (angle + 2.0).cos() * 0.8;
                    let dz2 = size * (angle + 2.0).sin() * 0.8;

                    let p0 = center + Vec3::new(0.0, 0.0, 0.0);
                    let p1 = center + Vec3::new(dx1, random_real_interval(&mut rng, 0.0, 0.2), dz1);
                    let p2 = center + Vec3::new(dx2, random_real_interval(&mut rng, 0.0, 0.2), dz2);

                    let color = Color::new(random_real(&mut rng), random_real(&mut rng), random_real(&mut rng));
                    let albedo = color.hadamard_product(color);
                    let material_tri = Arc::new(Lambertian::from_color(albedo));
                    world.push(Box::new(Triangle::new(p0, p1, p2, material_tri)));
                }
                else if choose_mat < 0.93 {
                    // metallic triangles
                    let size = random_real_interval(&mut rng, 0.05, 0.6);
                    let angle = random_real_interval(&mut rng, 0.0, std::f64::consts::PI * 2.0);
                    let p0 = center + Vec3::new(0.0, 0.0, 0.0);
                    let p1 = center + Vec3::new(size * angle.cos(), random_real_interval(&mut rng, 0.0, 0.1), size * angle.sin());
                    let p2 = center + Vec3::new(size * (angle + 1.2).cos(), random_real_interval(&mut rng, 0.0, 0.1), size * (angle + 1.2).sin());

                    let color = Color::new(
                        random_real_interval(&mut rng, 0.4, 1.0),
                        random_real_interval(&mut rng, 0.4, 1.0),
                        random_real_interval(&mut rng, 0.4, 1.0)
                    );
                    let fuzz = random_real_interval(&mut rng, 0.0, 0.6);
                    let material_tri = Arc::new(Metal::from_color(color, fuzz));
                    world.push(Box::new(Triangle::new(p0, p1, p2, material_tri)));
                }
                else {
                    // glass-like triangles
                    let size = random_real_interval(&mut rng, 0.1, 0.7);
                    let angle = random_real_interval(&mut rng, 0.0, std::f64::consts::PI * 2.0);
                    let p0 = center + Vec3::new(0.0, 0.0, 0.0);
                    let p1 = center + Vec3::new(size * angle.cos(), random_real_interval(&mut rng, 0.0, 0.15), size * angle.sin());
                    let p2 = center + Vec3::new(size * (angle + 1.7).cos(), random_real_interval(&mut rng, 0.0, 0.15), size * (angle + 1.7).sin());

                    let material_tri = Arc::new(Dielectric::new(1.5));
                    world.push(Box::new(Triangle::new(p0, p1, p2, material_tri)));
                }
            }
        }
    }

    // add many more triangle shards to create a 'fragment' field
    // dense small fragments
    for _cluster in 0..200 {
        let cx = random_real_interval(&mut rng, -12.0, 12.0);
        let cz = random_real_interval(&mut rng, -12.0, 12.0);
        let cy = random_real_interval(&mut rng, 0.0, 3.0);
        let pieces = random_integer_interval(&mut rng, 3, 12);
        for _ in 0..pieces {
            let center = Point3::new(
                cx + random_real_interval(&mut rng, -0.6, 0.6),
                cy + random_real_interval(&mut rng, -0.2, 0.8),
                cz + random_real_interval(&mut rng, -0.6, 0.6)
            );

            let size = random_real_interval(&mut rng, 0.02, 0.6);
            let a_ang = random_real_interval(&mut rng, 0.0, std::f64::consts::PI * 2.0);
            let b_ang = a_ang + random_real_interval(&mut rng, 0.6, 2.5);

            let p0 = center + Vec3::new(0.0, 0.0, 0.0);
            let p1 = center + Vec3::new(size * a_ang.cos(), random_real_interval(&mut rng, -0.1, 0.6), size * a_ang.sin());
            let p2 = center + Vec3::new(size * b_ang.cos(), random_real_interval(&mut rng, -0.1, 0.6), size * b_ang.sin());

            let choose_mat = random_real(&mut rng);
            if choose_mat < 0.7 {
                let color = Color::new(random_real(&mut rng), random_real(&mut rng), random_real(&mut rng));
                let albedo = color.hadamard_product(color);
                let material_tri = Arc::new(Lambertian::from_color(albedo));
                world.push(Box::new(Triangle::new(p0, p1, p2, material_tri)));
            } else if choose_mat < 0.92 {
                let color = Color::new(
                    random_real_interval(&mut rng, 0.3, 1.0),
                    random_real_interval(&mut rng, 0.3, 1.0),
                    random_real_interval(&mut rng, 0.3, 1.0)
                );
                let fuzz = random_real_interval(&mut rng, 0.0, 0.8);
                let material_tri = Arc::new(Metal::from_color(color, fuzz));
                world.push(Box::new(Triangle::new(p0, p1, p2, material_tri)));
            } else {
                let material_tri = Arc::new(Dielectric::new(1.5));
                world.push(Box::new(Triangle::new(p0, p1, p2, material_tri)));
            }
        }
    }

    // add some larger shards
    for _big in 0..60 {
        let center = Point3::new(
            random_real_interval(&mut rng, -10.0, 10.0),
            random_real_interval(&mut rng, 0.2, 4.0),
            random_real_interval(&mut rng, -10.0, 10.0)
        );
        let size = random_real_interval(&mut rng, 0.6, 3.0);
        let ang = random_real_interval(&mut rng, 0.0, std::f64::consts::PI * 2.0);

        let p0 = center + Vec3::new(0.0, 0.0, 0.0);
        let p1 = center + Vec3::new(size * ang.cos(), random_real_interval(&mut rng, -0.5, 1.0), size * ang.sin());
        let p2 = center + Vec3::new(size * (ang + 1.3).cos(), random_real_interval(&mut rng, -0.5, 1.0), size * (ang + 1.3).sin());

        let choose_mat = random_real(&mut rng);
        if choose_mat < 0.6 {
            let color = Color::new(random_real(&mut rng), random_real(&mut rng), random_real(&mut rng));
            let albedo = color.hadamard_product(color);
            let material_tri = Arc::new(Lambertian::from_color(albedo));
            world.push(Box::new(Triangle::new(p0, p1, p2, material_tri)));
        } else if choose_mat < 0.9 {
            let color = Color::new(
                random_real_interval(&mut rng, 0.4, 1.0),
                random_real_interval(&mut rng, 0.4, 1.0),
                random_real_interval(&mut rng, 0.4, 1.0)
            );
            let fuzz = random_real_interval(&mut rng, 0.0, 0.6);
            let material_tri = Arc::new(Metal::from_color(color, fuzz));
            world.push(Box::new(Triangle::new(p0, p1, p2, material_tri)));
        } else {
            let material_tri = Arc::new(Dielectric::new(1.5));
            world.push(Box::new(Triangle::new(p0, p1, p2, material_tri)));
        }
    }

    let cam = Camera::new(16.0 / 9.0, 400,
            100, 50, 20.0,
            Point3::new(-13.0, 2.0, 3.0),
            Point3::new(0.0, 0.0, 0.0),
            Vec3::new(0.0, 1.0, 0.0),
            0.6, 10.0,
            Color::new(0.70, 0.80, 1.00));
    
    let world = HittableList::to_bvh(world, &mut rng);
    
    cam.render(&world);
}
